"""
relay_mw — 文件中间件（inbox / outbox 消息队列）
完全替代 SQLite，使用目录 + 文件名序号实现 FIFO
"""
import json
import os
import time
import threading

BASE = os.path.expanduser('~/relay_mw')
INBOX_DIR = os.path.join(BASE, 'inbox')
OUTBOX_DIR = os.path.join(BASE, 'outbox')
_lock = threading.Lock()


def _ensure_dirs():
    os.makedirs(INBOX_DIR, exist_ok=True)
    os.makedirs(OUTBOX_DIR, exist_ok=True)


def init_db():
    """初始化文件目录（兼容旧接口名）"""
    _ensure_dirs()


# ─── inbox：ws_daemon 写入 → relay_node 读取 ─────────

def push_inbox(msg_type, payload, relay_id=''):
    """写一条 inbox 消息"""
    with _lock:
        _ensure_dirs()
        ts = int(time.time() * 1000000)
        fname = f'{ts:020d}_{relay_id}_{msg_type}.json'
        path = os.path.join(INBOX_DIR, fname)
        tmp = path + '.tmp'
        data = {
            'msg_type': msg_type,
            'payload': payload,
            'relay_id': relay_id,
            'created_at': time.time(),
        }
        with open(tmp, 'w') as f:
            json.dump(data, f, ensure_ascii=False)
        os.replace(tmp, path)


def pop_inbox():
    """取一条最旧未处理的 inbox 消息"""
    with _lock:
        _ensure_dirs()
        try:
            files = sorted(os.listdir(INBOX_DIR))
        except FileNotFoundError:
            return None

        for fname in files:
            if not fname.endswith('.json'):
                continue
            path = os.path.join(INBOX_DIR, fname)
            try:
                with open(path, 'r') as f:
                    data = json.load(f)
                os.remove(path)
                return {
                    'msg_type': data.get('msg_type', ''),
                    'payload': data.get('payload', {}),
                    'relay_id': data.get('relay_id', ''),
                }
            except (json.JSONDecodeError, OSError):
                try:
                    os.remove(path)
                except OSError:
                    pass
                continue
        return None


def count_inbox():
    """查看未处理消息数"""
    try:
        return len([f for f in os.listdir(INBOX_DIR) if f.endswith('.json')])
    except FileNotFoundError:
        return 0


# ─── outbox：relay_node 写入 → ws_daemon 读取并发送 ─────

def push_outbox(payload):
    """写一条 outbox 消息"""
    with _lock:
        _ensure_dirs()
        ts = int(time.time() * 1000000)
        fname = f'{ts:020d}.json'
        path = os.path.join(OUTBOX_DIR, fname)
        tmp = path + '.tmp'
        with open(tmp, 'w') as f:
            json.dump(payload, f, ensure_ascii=False)
        os.replace(tmp, path)


def pop_outbox():
    """取一条最旧未发送的 outbox 消息"""
    with _lock:
        _ensure_dirs()
        try:
            files = sorted(os.listdir(OUTBOX_DIR))
        except FileNotFoundError:
            return None

        for fname in files:
            if not fname.endswith('.json'):
                continue
            path = os.path.join(OUTBOX_DIR, fname)
            try:
                with open(path, 'r') as f:
                    data = json.load(f)
                os.remove(path)
                return data
            except (json.JSONDecodeError, OSError):
                try:
                    os.remove(path)
                except OSError:
                    pass
                continue
        return None
